import { Link, Outlet, useNavigate } from "react-router-dom";
import "./style/styleLayout.css";
import "./style/styleFoLayout.css";
import {
  TKProvider,
  useDispatchTT,
  useSelectorUser,
} from "../useHook/useReDux";

export function Layout() {
  return (
    <TKProvider>
      <Navbar />
      <Outlet />
      <Footer />
    </TKProvider>
  );
}

export function Navbar() {
  const [se] = useSelectorUser();
  const [dis] = useDispatchTT();
  const nv = useNavigate();
  return (
    <div className="navbar">
      <span>
        {se.authenticated == true ? (
          <Link to={"/chat_2ko3ia11o4qg5/chat"}>Chat</Link>
        ) : (
          ""
        )}
      </span>
      <span>
        {se.authenticated == true ? (
          <>
            <a
              href="#"
              onClick={(e) => {
                e.preventDefault();
                dis("logout");
                nv("/chat_2ko3ia11o4qg5");
              }}
            >
              Signout
            </a>
            {"  "}
            <span>{se.userId}</span>
          </>
        ) : (
          <span></span>
        )}
      </span>
    </div>
  );
}

export function Footer() {
  let da = new Date();
  return (
    <div className="footer">
      {da.getDate() + "/" + (da.getMonth() + 1) + "/" + da.getFullYear()}
    </div>
  );
}
