import "./style/styleChat.css";
import "./style/styleFoChat.css";
import image from "../assets/img/send.jpg";
import { linkAPI, docchat, nhapchat } from "../link/link.js";
import { useEffect, useRef, useState } from "react";
import { useSelectorChat, useSelectorUser } from "../useHook/useReDux";
const io = require("socket.io-client");
const socket = io(linkAPI);

export function Chat() {
  const [seu] = useSelectorUser();
  const [state, setState] = useState([]);
  const refIn = useRef("");

  useEffect(() => {
    setTimeout(() => {
      fetch(docchat)
        .then((x) => x.json())
        .then((y) => {
          setState(y);
        })
        .catch((er) => console.log(er.message));
    }, 1500);
    socket.on("message", (message) => {
      setState(message);
    });
    return () => {
      socket.off("message");
    };
  }, []);
  console.log("state: ", state);
  useEffect(() => {
    const mydiv = document.querySelector(".s2");
    mydiv.scrollTop = mydiv.scrollHeight;
  });
  function send() {
    const tt = {
      userId: seu.userId,
      content: refIn.current.value,
    };
    const st = [...state];
    st.push(tt);
    refIn.current.value = "";
    socket.emit("message", st);

    fetch(nhapchat, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(st),
    })
      .then((x) => x.json())
      .then((y) => {
        console.log(y.msg);
      })
      .catch((er) => console.log(er.message));
  }

  return (
    <div className="container2">
      <div className="s1">CHAT</div>
      <div className="s2">
        {state.map((x) =>
          x.userId == seu.userId ? (
            <div className="me">
              <span className="content">{x.content} </span>
              <span className="nick"> : {x.userId}</span>
            </div>
          ) : (
            <div className="you">
              <span className="nick">{x.userId} : </span>
              <span className="content">{x.content} </span>
            </div>
          ),
        )}
      </div>
      <div className="s3">
        <input type="text" id="txtInput" ref={refIn} />
        <a
          href="#"
          id="btnSend"
          onClick={(e) => {
            e.preventDefault();
            send();
          }}
        >
          <img src={image} />
        </a>
      </div>
    </div>
  );
}
