import { useEffect, useRef } from "react";
import "./style/styleHome.css";
import "./style/styleFoHome.css";
import { login, signup } from "../link/link.js";
import { useDispatchTT, useSelectorUser } from "../useHook/useReDux.js";
import { useNavigate } from "react-router-dom";

export function Home() {
  const refUserId = useRef("");
  const refPass = useRef("");
  const [dis] = useDispatchTT();
  const nv = useNavigate();
  function signupT() {
    if (refUserId.current.value == "" || refPass.current.value == "") {
      alert("userId hoặc Pass không được trống");
      return;
    }
    const info = {
      userId: refUserId.current.value,
      pass: refPass.current.value,
    };
    fetch(signup, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(info),
    })
      .then((x) => x.json())
      .then((y) => {
        dis("signup", y);
      })
      .catch((err) => console.log(err.message));
  }
  function loginT() {
    const info = {
      userId: refUserId.current.value,
      pass: refPass.current.value,
    };
    fetch(login, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(info),
    })
      .then((x) => x.json())
      .then((y) => {
        dis("login", y);
        if (y.user) nv("/chat_2ko3ia11o4qg5/chat");
      })
      .catch((err) => console.log(err.message));
  }
  return (
    <>
      <h2 className="h2">Sign In</h2>
      <div className="container">
        <span>Username</span>
        <input type="text" id="txtId" ref={refUserId} />
        <span>Password</span>
        <input type="password" id="txtPass" ref={refPass} />
        <div className="button">
          <button
            id="btnLogin"
            onClick={(e) => {
              e.preventDefault();
              loginT();
            }}
          >
            Login
          </button>
          <button
            href="#"
            id="btnSignUp"
            onClick={(e) => {
              e.preventDefault();
              signupT();
            }}
          >
            Sign Up
          </button>
        </div>
      </div>
    </>
  );
}
