import { Provider, useDispatch, useSelector } from "react-redux";
import { createSlice, configureStore } from "@reduxjs/toolkit";

const init_state_user = {
  authenticated: false,
  userId: "",
};

const userSlice = createSlice({
  name: "user",
  initialState: init_state_user,
  reducers: {
    login(state, action) {
      alert(action.payload.thongbao);
      if (action.payload.user) {
        state.userId = action.payload.user.userId;
        state.authenticated = true;
      } else {
        state.userId = "";
        state.authenticated = false;
      }
    },
    signup(state, action) {
      alert(action.payload.msg);
    },
    logout(state, action) {
      state.authenticated = false;
      state.userId = "";
    },
  },
});

const store = configureStore({
  reducer: { user: userSlice.reducer },
});

const userAction = userSlice.actions;

// ================== TKPROVIDER ================================
export function TKProvider(props) {
  return <Provider store={store}>{props.children}</Provider>;
}
// ==============================================================

export function useSelectorUser() {
  const se = useSelector((x) => x.user);
  return [se];
}

export function useDispatchTT() {
  const dis = useDispatch();
  const diss = (type, pay) => {
    switch (type) {
      case "login": {
        dis(userAction.login(pay));
        break;
      }
      case "logout": {
        dis(userAction.logout());
        break;
      }
      case "signup": {
        dis(userAction.signup(pay));
        break;
      }
      default:
        break;
    }
  };
  return [diss];
}
